import 'package:flutter/material.dart';import '../services/api_service.dart';import '../widgets/app_sidebar.dart';
class BrainBoosterScreen extends StatefulWidget{const BrainBoosterScreen({super.key});@override State<BrainBoosterScreen> createState()=>_State();}
class _State extends State<BrainBoosterScreen>{final api=ApiService();late Future<Map<String,dynamic>> data;final answers=<int,int>{};@override void initState(){super.initState();reload();}void reload()=>setState(()=>data=api.getDailyBooster());Future<void> submit()async{final result=await api.submitDailyBooster(answers);if(mounted)await showDialog(context:context,builder:(c)=>AlertDialog(title:const Text('Booster complete!'),content:Text('Score: ${result['score']}/${result['total']}\nXP earned: +${result['xp_earned']}'),actions:[FilledButton(onPressed:()=>Navigator.pop(c),child:const Text('Done'))]));reload();}@override Widget build(BuildContext context)=>Scaffold(drawer:const AppSidebar(role:'participant'),appBar:AppBar(title:const Text('Daily Brain Booster'),actions:[IconButton(onPressed:reload,icon:const Icon(Icons.refresh))]),body:FutureBuilder<Map<String,dynamic>>(future:data,builder:(c,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());if(s.hasError)return Center(child:Text('Could not load booster: ${s.error}'));final d=s.data!;if(d['available']!=true)return Center(child:Column(mainAxisSize:MainAxisSize.min,children:[const Text('⚡',style:TextStyle(fontSize:64)),const Text('Today’s booster is complete!',style:TextStyle(fontSize:22,fontWeight:FontWeight.bold)),Text('Score ${d['score']??0}/3 • +${d['xp_earned']??0} XP'),const Text('Come back tomorrow for another challenge.')])) ;final questions=List<Map<String,dynamic>>.from(d['questions']??const[]);return ListView(padding:const EdgeInsets.all(20),children:[const Text('Answer three questions to earn up to 45 XP.',style:TextStyle(fontSize:18)),...questions.asMap().entries.map((entry){final q=entry.value,id=q['id'] as int,options=List<Map<String,dynamic>>.from(q['options']);return Card(child:Padding(padding:const EdgeInsets.all(16),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('Q${entry.key+1}. ${q['text']}',style:const TextStyle(fontWeight:FontWeight.bold)),...options.map((o)=>RadioListTile<int>(value:o['id'] as int,groupValue:answers[id],title:Text(o['text'].toString()),onChanged:(v)=>setState(()=>answers[id]=v!)))])));}),Align(alignment:Alignment.centerRight,child:FilledButton.icon(onPressed:answers.length==questions.length?submit:null,icon:const Icon(Icons.bolt),label:const Text('Submit answers')))]); }));}
